    """
    Computes the bounds of the object in the form
    [[lat_min, lon_min], [lat_max, lon_max]]

    """
    bounds = [[None, None], [None, None]]
    if isinstance(locations, dict) and locations.get('type') == 'GeometryCollection':
        # Handle GeometryCollection by iterating over geometries
        for geometry in locations.get('geometries', []):
            if geometry.get('type') == 'Polygon':
                # Compute bounds for each Polygon
                for point in iter_coords(geometry.get('coordinates')):
                    bounds = [
                        [
                            none_min(bounds[0][0], point[0]),
                            none_min(bounds[0][1], point[1]),
                        ],
                        [
                            none_max(bounds[1][0], point[0]),
                            none_max(bounds[1][1], point[1]),
                        ],
                    ]
    else:
        for point in iter_coords(locations):
            bounds = [
                [
                    none_min(bounds[0][0], point[0]),
                    none_min(bounds[0][1], point[1]),
                ],
                [
                    none_max(bounds[1][0], point[0]),
                    none_max(bounds[1][1], point[1]),
                ],
            ]
    if lonlat:
        bounds = _locations_mirror(bounds)
    return bounds
